import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from 'react-router-dom';

// Importurile tale
import VideoBackground from './assets/backgroundVideo.mp4';
import logoImage from '../public/favicon.jpg';
import './App.css';

// Importă componentele paginii
import Login from './components/Login';
import Register from './components/Register';
import ProfilePage from './components/ProfilePage';

// O componentă mică pentru Logout, ca să putem folosi 'useNavigate'
const LogoutButton: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
    const navigate = useNavigate();

    const handleClick = () => {
        onLogout(); // Șterge starea din App.tsx
        navigate('/login'); // Redirecționează la login
    };

    return (
        <button onClick={handleClick} className="nav-button logout-button">
            Logout
        </button>
    );
};


const App: React.FC = () => {
    // 1. Starea de autentificare. Începem prin a citi din localStorage.
    const [currentUser, setCurrentUser] = useState<string | null>(
        localStorage.getItem('username')
    );

    // 2. Funcție pentru a actualiza starea la login
    const handleLogin = (username: string) => {
        setCurrentUser(username);
    };

    // 3. Funcție pentru delogare
    const handleLogout = () => {
        setCurrentUser(null);
        localStorage.removeItem('token');
        localStorage.removeItem('username');
        localStorage.removeItem('userId'); // Șterge tot ce e legat de user
    };

    return (
        <Router>
            <div>
                <VideoBackground />

                <nav className="nav-container">
                    <Link to="/">
                        <img src={logoImage} alt="Math App Logo" className="logo-image" />
                    </Link>

                    {/* 4. AICI ESTE CONDIȚIA */}
                    <div className="nav-buttons">
                        {currentUser ? (
                            // ------ DACĂ ESTE LOGAT ------
                            <>
                                <span className="welcome-user">Bun venit, {currentUser}!</span>
                                <Link to="/profile" className="nav-button">Profil</Link>
                                <LogoutButton onLogout={handleLogout} />
                            </>
                        ) : (
                            // ------ DACĂ NU ESTE LOGAT ------
                            <>
                                <Link to="/login" className="nav-button">Login</Link>
                                <Link to="/register" className="nav-button">Register</Link>
                            </>
                        )}
                    </div>
                </nav>

                <div className="content-container">
                    <Routes>
                        {/* 5. Trimitem funcția 'handleLogin' către componenta Login */}
                        <Route path="/login" element={<Login onLoginSuccess={handleLogin} />} />
                        <Route path="/register" element={<Register />} />
                        <Route path="/profile" element={<ProfilePage />} />
                        <Route path="/" element={<h1>Bun venit!</h1>} />
                    </Routes>
                </div>
            </div>
        </Router>
    );
};

export default App;
